mapper.select:
SELECT p.policy_id, p.policy_number, p.insured_name, p.status, p.agent_id, u1.name AS agent_name, -- 業務員姓名 p.reviewer_id, u2.name AS reviewer_name, -- 最後審核者姓名 p.last_reviewed_date -- 最後審核時間 FROM policies p LEFT JOIN users u1 ON p.agent_id = u1.id LEFT JOIN users u2 ON p.reviewer_id = u2.id
AND p.agent_id = #{userId}
ORDER BY p.policy_id DESC
